fun circuitBreakerRegistry(): CircuitBreakerRegistry {
    val config = CircuitBreakerConfig.custom()
        .slidingWindowSize(10).failureRateThreshold(50f)
        .waitDurationInOpenState(Duration.ofSeconds(30)).build()
}

